INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-01339', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關驗配軟式隱形眼鏡的敘述，下列何者錯誤？', '["改善配適狀態時，要修改鏡片參數，建議優先修改鏡片直徑，若試戴後不理想則再修改鏡片基弧", "鏡片直徑與鏡片基弧之間的關係變化，與鏡片矢高的大小變化有直接的相關連", "當鏡片基弧每增加0.3mm，鏡片配適變化的狀態與鏡片直徑減少0.5mm相似", "軟式隱形眼鏡的配適變化，軟式隱形眼鏡的基弧至少要改變0.8mm以上，配適的鬆緊才會有顯著不同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01340', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於角膜弧度的測量，下列敘述何者正確？', '["角膜弧度43.00D@180/43.00D@090，表示眼睛沒有散光", "一般傳統角膜弧度儀測量原理中，是假設角膜中心為球面", "角膜曲率半徑愈大表示屈光度愈大，罹患近視的可能性也大", "垂直主經線測得的角膜曲率半徑值比水平主經線大，稱為順性散光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01341', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於以螢光染色劑來評估硬式隱形眼鏡的驗配，下列敘述何者錯誤？', '["可評估角膜的形狀及與隱形眼鏡對應的關係", "鏡片的基弧比角膜弧度大的時候，角膜中央會有螢光染色劑的堆積", "根據染色的型態可預估散光的軸度及程度", "螢光染色劑也可用來評估淚液的品質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01342', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關細隙燈顯微鏡檢查的照明方法，下列敘述何者錯誤？', '["彌散光照射法（diffuseillumination）是最基本的照明技術，是用毛玻璃濾光片將光線擴散", "角鞏膜緣漫射法（scleroticscatter）可以觀察到中心角膜水腫（centralcornealedema）", "背面反射照明法（retroillumination）可以觀察到角膜神經纖維", "光學切面照明法（opticsection）可以觀察到角膜異物的深度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01343', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列那項眼球微細的變化，無法以細隙燈顯微鏡檢查出來？', '["輪部新生血管", "前房細胞", "角膜地形", "角膜水腫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01344', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜內皮細胞多形狀症（polymegathism）的敘述，下列何者正確？', '["角膜在長期慢性的缺氧狀態下，內皮細胞會變得不規則形狀", "細隙燈使用放大倍率16倍的鏡面反射法（specularreflectiontechnique），即可觀察得到", "不戴隱形眼鏡或更換戴高透氧隱形眼鏡以後，則變形內皮細胞可能會慢慢回復原規則的形狀", "配戴硬式高透氧鏡片更是常發生此併發症"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01345', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關巨乳突狀結膜炎之敘述，下列何者錯誤？', '["增加鏡片的更換頻率或使用拋棄式軟式隱形眼鏡，可減少產生巨乳突狀結膜炎機會", "是因配戴隱形眼鏡引起的化學性刺激或物理性刺激，因而導致下瞼結膜發炎引起的", "有巨乳突狀結膜炎時的處理方法包括先停止配戴鏡片至眼科就診，痊癒後要更換新隱形眼鏡再配戴、定 期保養清潔及要遵守鏡片的使用期限", "有巨乳突狀結膜炎時，病人會感覺鏡片容易滑動且視力不穩定和有異物感"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01346', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於治療型軟式隱形眼鏡的敘述，下列何者錯誤？', '["治療型軟式隱形眼鏡可幫助減少疼痛", "治療型軟式隱形眼鏡，一般是日戴型", "配戴治療型軟式隱形眼鏡時，建議盡量使用不含防腐劑的眼藥水", "治療型軟式隱形眼鏡常採用的是高透氧矽水膠材質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01347', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '使用螢光染色劑來觀察是否有角膜破皮，最好將細隙燈的光線調成何種顏色？', '["黃光", "藍光", "紅光", "白光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01348', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡配戴的敘述，下列何者錯誤？', '["乾眼是隱形眼鏡配戴者最常見的併發症", "常見的原因是眼睛淚液分泌不足或是淚液蒸發過度", "長期配戴隱形眼鏡，經常會導致角膜之敏感度增加，也會影響淚液之分泌", "造成淚液油脂層、黏液層分泌不足的疾病也會引發乾眼症"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
